import type { MetricsStore } from './types';

import { createHotjarStore } from './hotjar';
import { createGTMStore } from './gtm';
import { createQualtricsInsightsStore } from './qualtrics-insights';

export async function createMetricsStore(): Promise<MetricsStore> {
  const [hotjar, googleTagManager] = await Promise.all([
    createHotjarStore(),
    createGTMStore(),
  ]);

  return {
    hotjar,
    googleTagManager,
    qualtricsInsights: createQualtricsInsightsStore(),
  };
}
